import{c as a,Q as r,j as t,m as s}from"./chunks/framework.CdiUUa3G.js";const m=JSON.parse('{"title":"ADR-009 — Free-return flyby as mission scenario","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-009.md","filePath":"adr/ADR-009.md"}'),i={name:"adr/ADR-009.md"};function n(o,e,l,c,d,u){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="adr-009-—-free-return-flyby-as-mission-scenario" tabindex="-1">ADR-009 — Free-return flyby as mission scenario <a class="header-anchor" href="#adr-009-—-free-return-flyby-as-mission-scenario" aria-label="Permalink to &quot;ADR-009 — Free-return flyby as mission scenario&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-15 TA anchor · §components/fly-screen</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The fly screen needed a mission scenario. The original prototype used a Mars orbit insertion (MOI) scenario — outbound only, 259 days, spacecraft enters Mars orbit. During development this was reconsidered.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>The default mission scenario (ORRERY-1) is a free-return Mars flyby: 259 days outbound, Mars closest approach at ~300 km altitude, 250 days return to Earth. Total 509 days. No landing. No MOI burn.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>A free-return trajectory is analogous to Artemis II at interplanetary scale — a real mission architecture studied for crewed Mars missions. It is more physically interesting than a one-way cruise: the spacecraft returns to Earth, the return arc is distinct from the outbound arc, and the gravity assist at Mars is meaningful. It also requires less delta-v (no MOI burn), making the mission viable on a Falcon Heavy with 2,500 kg payload — the chosen vehicle.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li>Mars orbit insertion — simpler single-arc trajectory; less interesting; requires 2.21 km/s MOI burn that consumes most remaining propellant.</li><li>Mars landing scenario — requires atmospheric entry physics not implemented in the physics library; out of scope for v1.</li><li>Multiple selectable scenarios — good long-term feature; adds complexity to the fly screen data model. v2 candidate.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: physically richer scenario; two distinct arc segments visible on screen; CAPCOM events span the full 509-day mission including return. Negative: 509-day simulation is longer to scrub through; the &quot;mission arrives&quot; completion state is Earth return, not Mars arrival — some users may expect Mars landing.</p>',12)])])}const p=a(i,[["render",n]]);export{m as __pageData,p as default};
